import Button from "../../components/Login/Button";
import Input from "../../components/Login/Input";
import TextButton from "../../components/Login/TextButton";
import useInput from "../../hooks/useInput";
import classes from "./Login.module.css";

const Login = (props) => {
  const {
    value: enteredEmail,
    shouldDisplayError: emailDisplayError,
    isValid: emailIsValid,
    valueChangeHandler: emailChangeHandler,
    onBlurHandler: emailBlurHandler,
    reset: resetEmail,
  } = useInput((value) => value.includes("@"));

  const {
    value: enteredPassword,
    shouldDisplayError: passwordDisplayError,
    isValid: passwordIsValid,
    valueChangeHandler: passwordChangeHandler,
    onBlurHandler: passwordBlurHandler,
    reset: resetPassword,
  } = useInput((value) => value.trim() !== "");

  let displayError = false;

  const loginHandler = async (event) => {
    event.preventDefault();

    const data = { email: enteredEmail, password: enteredPassword };

    try {
      const response = await fetch("/auth/login", {
        method: "POST",
        body: JSON.stringify(data),
        headers: { "Content-Type": "application/json" },
      });

      let loggedinData = await response.json();
      console.log(loggedinData);
    } catch (err) {
      console.log(err);
    }

    if (passwordDisplayError || emailDisplayError) {
      // console.log("HERE")
      // displayError = true;
    }

    if (!passwordIsValid || !emailIsValid) {
      return;
    }

    resetEmail();
    resetPassword();
  };

  // console.log("RERENDERING FORM");

  return (
    <div className={classes["wrapper"]}>
      <form className={classes["form"]} onSubmit={loginHandler}>
        <div className={classes["header"]}>
          <h1 className={classes["heading"]}>Welcome back!</h1>
          <div className={classes["header-text"]}>
            We're so excited to see you again!
          </div>
        </div>
        <div className={classes["block"]}>
          <Input
            name="email"
            label="email"
            type="text"
            onChange={emailChangeHandler}
            onBlur={emailBlurHandler}
            value={enteredEmail}
            hasError={displayError}
          ></Input>
          <Input
            name="password"
            label="password"
            type="password"
            onChange={passwordChangeHandler}
            onBlur={passwordBlurHandler}
            value={enteredPassword}
            hasError={displayError}
          ></Input>
          <Button type="submit">Log In</Button>
          <div>
            <span className={classes["text"]}>Need an account?</span>
            <TextButton link="/register">Register</TextButton>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Login;
